class Complex {
private:
 double real, imag;
public:
 Complex(double r = 0, double i = 0) : real(r), imag(i) {}

 // Binary + operator as member function
 Complex operator+(const Complex& rhs) const {
 Complex result;
 result.real = this->real + rhs.real;
 result.imag = this->imag + rhs.imag;
 return result;
 }

 void display() const {
 cout << real << " + " << imag << "i" << endl;
 }
};

// Usage:
// Complex c1(3, 4), c2(1, 2), c3;
// c3 = c1 + c2; // Translates to c1.operator+(c2)

class Counter {
private:
 int count;
public:
 Counter(int c = 0) : count(c) {}

 // Prefix ++ operator (unary, no parameters)
 Counter& operator++() {
 ++this->count;
 return *this; // Return reference for chaining
 }

 // Postfix ++ operator (unary, takes dummy int parameter)
 Counter operator++(int) {
 Counter temp = *this;
 this->count++;
 return temp; // Return copy (old value)
 }

 int getCount() const { return count; }
};

// Usage:
// Counter c(5);
// ++c; // c.getCount() = 6, returns reference
// c++; // c.getCount() = 7, returns old copy

class String {
private:
 char* str;
 int len;
public:
 String(const char* s = "") {
 len = strlen(s);
 str = new char[len + 1];
 strcpy(str, s);
 }

 // Compound assignment as member function
 String& operator+=(const String& rhs) {
 char* temp = new char[len + rhs.len + 1];
 strcpy(temp, str);
 strcat(temp, rhs.str);
 delete[] str;
 str = temp;
 len = len + rhs.len;
 return *this; // Enable chaining: a += b += c
 }

 void display() const { cout << str; }
};

// Usage:
// String s1("Hello"), s2(" World");
// s1 += s2; // s1 = "Hello World"
// s1 += s2 += s2; // Chaining works

class Date {
private:
 int day, month, year;
public:
 Date(int d, int m, int y) : day(d), month(m), year(y) {}

 // Equality operator
 bool operator==(const Date& rhs) const {
 return (this->day == rhs.day && 
 this->month == rhs.month && 
 this->year == rhs.year);
 }

 // Less than operator
 bool operator<(const Date& rhs) const {
 if (this->year != rhs.year)
 return this->year < rhs.year;
 if (this->month != rhs.month)
 return this->month < rhs.month;
 return this->day < rhs.day;
 }

 // Other comparisons can use these
 bool operator!=(const Date& rhs) const {
 return !(*this == rhs);
 }

 bool operator>(const Date& rhs) const {
 return rhs < *this;
 }
};

// Usage:
// Date d1(15, 8, 2023), d2(20, 8, 2023);
// if (d1 < d2) // true

class SafeArray {
private:
 int arr[100];
 int size;
public:
 SafeArray(int s = 100) : size(s) {
 for(int i = 0; i < size; i++) arr[i] = 0;
 }

 // Subscript operator - MUST be member function
 int& operator[](int index) {
 if(index < 0 || index >= size) {
 throw out_of_range("Index out of bounds");
 }
 return arr[index];
 }

 // Const version for const objects
 const int& operator[](int index) const {
 if(index < 0 || index >= size) {
 throw out_of_range("Index out of bounds");
 }
 return arr[index];
 }
};

// Usage:
// SafeArray a(10);
// a[0] = 100;
// int x = a[5]; // Bounds checking done
